const input = $input.first().json;
const ZNUNY_URL = "https://ticket.doehlercomputing.de/znuny/nph-genericinterface.pl/Webservice/ZabbixIntegration";
const session = await this.helpers.httpRequest({
  method: "POST", url: `${ZNUNY_URL}/Session`,
  body: {UserLogin: "zabbix", Password: "ZabbixInt3gration!"},
  json: true, skipSslCertificateValidation: true
});
if (!session.SessionID) return [{json: {success: false, error: "Session failed"}}];

let ticketId = input.ticket_id;
if (!ticketId && input.zabbix_reference) {
  const search = await this.helpers.httpRequest({
    method: "GET",
    url: `${ZNUNY_URL}/Ticket?SessionID=${session.SessionID}&DynamicField_ZabbixReferenz=${encodeURIComponent(input.zabbix_reference)}`,
    json: true, skipSslCertificateValidation: true
  });
  ticketId = search.TicketID?.[0];
  if (!ticketId) return [{json: {success: false, error: "Ticket nicht gefunden"}}];
}
if (!ticketId) return [{json: {success: false, error: "Kein ticket_id/zabbix_reference"}}];

const ticket = await this.helpers.httpRequest({
  method: "GET",
  url: `${ZNUNY_URL}/Ticket/${ticketId}?SessionID=${session.SessionID}&AllArticles=1&DynamicFields=1`,
  json: true, skipSslCertificateValidation: true
});
if (!ticket.Ticket?.length) return [{json: {success: false, error: "Ticket nicht gefunden"}}];

const t = ticket.Ticket[0];
const df = {};
if (t.DynamicField) for (const f of t.DynamicField) df[f.Name] = f.Value;

return [{json: {
  success: true, ticket_id: t.TicketID, ticket_number: t.TicketNumber,
  title: t.Title, queue: t.Queue, state: t.State, priority: t.Priority,
  dynamic_fields: df,
  articles: (t.Article||[]).map(a => ({id: a.ArticleID, subject: a.Subject, body: a.Body, created: a.Created}))
}}];

